import strawberry
from strawberry.types import Info
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey
from sqlalchemy.orm import sessionmaker, relationship, declarative_base

Base = declarative_base()
engine = create_engine('sqlite:///example.db')
SessionLocal = sessionmaker(bind=engine)

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    reviews = relationship("Review", back_populates="product")
    seller_id = Column(Integer, ForeignKey('sellers.id'))
    seller = relationship("Seller", back_populates="products")
    category_id = Column(Integer, ForeignKey('categories.id'))
    category = relationship("Category", back_populates="products")
    images = relationship("Image", back_populates="product")

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    content = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship("Product", back_populates="reviews")

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship("Product", back_populates="seller")

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship("Product", back_populates="category")

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    url = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship("Product", back_populates="images")

Base.metadata.create_all(bind=engine)

@strawberry.type
class ReviewType:
    id: int
    content: str

@strawberry.type
class SellerType:
    id: int
    name: str

@strawberry.type
class CategoryType:
    id: int
    name: str

@strawberry.type
class ImageType:
    id: int
    url: str

@strawberry.type
class ProductType:
    id: int
    name: str
    reviews: list[ReviewType]
    seller: SellerType
    category: CategoryType
    images: list[ImageType]

def get_products(info: Info) -> list[ProductType]:
    db = SessionLocal()
    products = db.query(Product).all()
    return [
        ProductType(
            id=product.id,
            name=product.name,
            reviews=[
                ReviewType(id=review.id, content=review.content)
                for review in product.reviews
            ],
            seller=SellerType(id=product.seller.id, name=product.seller.name),
            category=CategoryType(id=product.category.id, name=product.category.name),
            images=[
                ImageType(id=image.id, url=image.url)
                for image in product.images
            ]
        )
        for product in products
    ]

@strawberry.type
class Query:
    products: list[ProductType] = strawberry.field(resolver=get_products)

schema = strawberry.Schema(query=Query)